1137	func ResolveGoverningRefs(root string, b *bead.Bead) []executeBeadGoverningRef {
1138		specIDRaw, _ := b.Extra["spec-id"].(string)
1139		specIDRaw = strings.TrimSpace(specIDRaw)
1140		if specIDRaw == "" {
1141			return nil
1142		}
1143	
1144		// spec-id may be a comma-separated list of IDs or paths.
1145		ids := strings.Split(specIDRaw, ",")
1146		graph, _ := docgraph.BuildGraphWithConfig(root)
1147	
1148		var refs []executeBeadGoverningRef
1149		for _, specID := range ids {
1150			specID = strings.TrimSpace(specID)
1151			if specID == "" {
1152				continue
1153			}
1154			if graph != nil {
1155				if doc, ok := graph.Documents[specID]; ok && doc != nil {
1156					refs = append(refs, executeBeadGoverningRef{
1157						ID:    doc.ID,
1158						Path:  filepath.ToSlash(strings.TrimPrefix(strings.TrimPrefix(doc.Path, root), string(filepath.Separator))),
1159						Title: doc.Title,
1160					})
1161					continue
1162				}
1163			}
1164			candidate := filepath.Clean(filepath.Join(root, filepath.FromSlash(specID)))
1165			relCandidate, relErr := filepath.Rel(root, candidate)
1166			if relErr != nil || strings.HasPrefix(relCandidate, ".."+string(filepath.Separator)) || relCandidate == ".." {
1167				continue
1168			}
1169			info, statErr := os.Stat(candidate)
1170			if statErr != nil || info.IsDir() {
1171				continue
1172			}
1173			refs = append(refs, executeBeadGoverningRef{
1174				ID:   specID,
1175				Path: filepath.ToSlash(relCandidate),
1176			})
1177		}
1178		return refs
1179	}
